import re
import hashlib
from datetime import datetime, timezone

NULL_VALUES = {'', 'nan', 'none', '-', 'n/a', 'null'}
TRUE_VALUES = {'true', 'yes', '1', 'done', 'processed'}
RETRY_STATUSES = {'pending', 'screening_error', 'resume_error'}

def clean(value):
    if value is None:
        return ''
    value = str(value).strip()
    return '' if value.lower() in NULL_VALUES else value

def truthy(value):
    return clean(value).lower() in TRUE_VALUES

def first_exact(data, keys):
    for key in keys:
        value = clean(data.get(key))
        if value:
            return value
    return ''

def find_field(data, exact_keys, keywords):
    value = first_exact(data, exact_keys)
    if value:
        return value
    for key, val in data.items():
        key_lower = str(key).lower().strip()
        if any(keyword.lower() in key_lower for keyword in keywords):
            val = clean(val)
            if val:
                return val
    return ''

def extract_drive_file_id(url):
    url = clean(url)
    patterns = [
        r'[?&]id=([^&#]+)',
        r'/d/([^/?#]+)',
        r'/file/d/([^/?#]+)',
        r'open\?id=([^&#]+)'
    ]
    for pattern in patterns:
        match = re.search(pattern, url)
        if match:
            return match.group(1).strip()
    if re.fullmatch(r'[A-Za-z0-9_-]{20,}', url):
        return url
    return ''

def candidate_id(email, role):
    raw = f'{email.lower()}|{role.upper()}'
    return f'{role.upper()}-{hashlib.sha256(raw.encode()).hexdigest()[:12].upper()}'

try:
    master_rows = _('Master_Sheet').all()
except Exception as exc:
    raise Exception(f'Master sheet read failed before candidate processing: {exc}')

existing_by_key = {}
existing_ids = set()
for record in master_rows:
    row = record.get('json', {}) if isinstance(record, dict) else getattr(record, 'json', {})
    email = clean(row.get('email')).lower()
    role = clean(row.get('role')).upper()
    cid = clean(row.get('Candidate ID'))
    if email and role:
        existing_by_key[f'{email}|{role}'] = row
    if cid:
        existing_ids.add(cid)

processed = []
skipped = []
seen_this_run = set()

for item in _input.all():
    data = item.get('json', {}) if isinstance(item, dict) else getattr(item, 'json', {})
    role = clean(data.get('role')).upper()
    if role not in {'SWE', 'BDM'}:
        continue

    source_row_number = clean(data.get('row_number'))
    source_processed = truthy(data.get('processed'))

    if role == 'SWE':
        name = find_field(data, ['Full Name'], ['full name', 'your name', 'name'])
        email = find_field(data, ['Email Address', 'Email address'], ['email'])
        resume_url = find_field(data, ['Resume / CV (PDF)', 'Resume'], ['resume', 'cv', 'upload'])
        experience = find_field(data, ['Programming Languages'], ['programming', 'language', 'skill', 'tech', 'experience'])
        extra_link = find_field(data, ['GitHub Profile Link'], ['github', 'portfolio'])
    else:
        name = find_field(data, ['Name'], ['full name', 'your name', 'name'])
        email = find_field(data, ['Contact Email', 'Email address', 'Email Address'], ['contact email', 'email'])
        resume_url = find_field(data, ['Resume'], ['resume', 'cv', 'upload'])
        experience = find_field(data, ['Years of Sales Experience'], ['experience', 'sales', 'year'])
        extra_link = find_field(data, ['LinkedIn Profile'], ['linkedin'])

    email = clean(email).lower()
    drive_file_id = extract_drive_file_id(resume_url)
    key = f'{email}|{role}'

    missing = []
    if not name: missing.append('name')
    if not email: missing.append('email')
    if not resume_url: missing.append('resume_url')
    if resume_url and not drive_file_id: missing.append('valid_drive_file_id')
    if missing:
        skipped.append({'email': email, 'role': role, 'reason': 'missing ' + ', '.join(missing), 'source_row_number': source_row_number})
        continue

    existing = existing_by_key.get(key)
    if key in seen_this_run:
        skipped.append({'email': email, 'role': role, 'reason': 'duplicate candidate in this run', 'source_row_number': source_row_number})
        continue

    if existing:
        existing_status = clean(existing.get('status')).lower()
        if existing_status not in RETRY_STATUSES:
            skipped.append({'email': email, 'role': role, 'reason': f'already processed with status {existing_status or "unknown"}', 'source_row_number': source_row_number})
            continue
        cid = clean(existing.get('Candidate ID')) or candidate_id(email, role)
    else:
        if source_processed:
            skipped.append({'email': email, 'role': role, 'reason': 'source row already marked processed but no retryable master record found', 'source_row_number': source_row_number})
            continue
        cid = candidate_id(email, role)
        if cid in existing_ids:
            skipped.append({'email': email, 'role': role, 'reason': 'candidate id already exists', 'source_row_number': source_row_number})
            continue

    seen_this_run.add(key)
    existing_ids.add(cid)
    processed.append({
        'json': {
            'Candidate ID': cid,
            'name': name,
            'email': email,
            'role': role,
            'experience': experience,
            'status': 'pending',
            'ai_score': '',
            'ai_classification': '',
            'ai_summary': '',
            'ai_strengths': '',
            'ai_concerns': '',
            'interview_recommended': '',
            'contacted': 'NO',
            'calendar_event_link': '',
            'extra_link': extra_link,
            'resume_url': resume_url,
            'drive_file_id': drive_file_id,
            'workflow_status': 'NEW',
            'source_sheet': role,
            'source_row_number': source_row_number,
            'error_note': '',
            'ingested_at': datetime.now(timezone.utc).isoformat()
        }
    })

if not processed:
    return [{
        'json': {
            'workflow_status': 'NO_NEW_CANDIDATES',
            'message': f'No valid new candidates. Skipped {len(skipped)} rows.',
            'skipped_rows': skipped[:25]
        }
    }]

return processed

