import json
import re

def get_json(item):
    if item is None:
        return {}

    if isinstance(item, dict):
        data = item.get('json', item)
    else:
        data = getattr(item, 'json', item)

    if hasattr(data, 'to_py'):
        data = data.to_py()

    if isinstance(data, dict):
        return data

    return {}

def to_int(value, default=0):
    try:
        return int(float(value))
    except Exception:
        return default

def to_text_list(value):
    if value is None:
        return ''
    if hasattr(value, 'to_py'):
        value = value.to_py()
    if isinstance(value, list):
        return ' | '.join([str(v) for v in value if str(v).strip()])
    return str(value)

def clean_raw_text(text):
    text = str(text or '').strip()

    # Remove reasoning blocks from reasoning models
    text = re.sub(r'<think>.*?</think>', '', text, flags=re.DOTALL | re.IGNORECASE)

    # Remove markdown code fences if present
    text = text.replace('```json', '').replace('```', '').strip()

    # If model returns JSON as a quoted string, unquote it
    if text.startswith('"') and text.endswith('"'):
        try:
            text = json.loads(text)
        except Exception:
            pass

    # Convert escaped JSON string into normal JSON text
    text = text.replace('\\n', '\n')
    text = text.replace('\\"', '"')

    return text.strip()

def parse_ai_from_text(text):
    text = clean_raw_text(text)

    # Try direct JSON parse
    try:
        parsed = json.loads(text)
        if isinstance(parsed, dict):
            return parsed
    except Exception:
        pass

    # Try JSON object inside text
    match = re.search(r'\{.*\}', text, re.DOTALL)
    if match:
        try:
            parsed = json.loads(match.group(0))
            if isinstance(parsed, dict):
                return parsed
        except Exception:
            pass

    return {}

def extract_ai_data(llm_json):
    # Case 1: Structured Output Parser success
    output = llm_json.get('output')
    if hasattr(output, 'to_py'):
        output = output.to_py()

    if isinstance(output, dict):
        return output

    # Case 2: Basic LLM Chain returns fields directly
    if (
        llm_json.get('score') is not None
        and llm_json.get('classification') is not None
        and llm_json.get('summary') is not None
    ):
        return llm_json

    # Case 3: Basic LLM Chain returns raw text / escaped JSON text
    raw_text = (
        llm_json.get('text')
        or llm_json.get('output')
        or llm_json.get('response')
        or llm_json.get('result')
        or ''
    )

    if isinstance(raw_text, dict):
        return raw_text

    return parse_ai_from_text(raw_text)

ai_items = _input.all()
original_items = _('Validate & Deduplicate Candidates').all()

output_items = []

for index, item in enumerate(ai_items):
    llm_json = get_json(item)

    if index < len(original_items):
        original_json = get_json(original_items[index])
    else:
        original_json = {}

    ai_data = extract_ai_data(llm_json)

    has_valid_ai = (
        isinstance(ai_data, dict)
        and ai_data.get('score') is not None
        and ai_data.get('classification') is not None
        and ai_data.get('summary') is not None
    )

    sheet_data = {}
    for key, value in original_json.items():
        sheet_data[key] = value

    if has_valid_ai:
        score = max(0, min(100, to_int(ai_data.get('score'))))

        classification = str(ai_data.get('classification', '')).lower().strip()

        # Force classification to match score
        if score >= 75:
            classification = 'strong'
        elif score >= 50:
            classification = 'average'
        else:
            classification = 'weak'

        interview_recommended = ai_data.get('interview_recommended', classification == 'strong')
        if isinstance(interview_recommended, str):
            interview_recommended = interview_recommended.strip().lower() in ['true', 'yes', '1']

        # Force interview recommendation to match final classification
        interview_recommended = classification == 'strong'

        sheet_data['ai_score'] = score
        sheet_data['ai_classification'] = classification
        sheet_data['ai_summary'] = str(ai_data.get('summary', ''))
        sheet_data['ai_strengths'] = to_text_list(ai_data.get('key_strengths'))
        sheet_data['ai_concerns'] = to_text_list(ai_data.get('concerns'))
        sheet_data['interview_recommended'] = 'YES' if interview_recommended else 'NO'
        sheet_data['status'] = 'screened'
        sheet_data['workflow_status'] = 'SCREENED'
        sheet_data['error_note'] = ''
    else:
        sheet_data['ai_score'] = ''
        sheet_data['ai_classification'] = ''
        sheet_data['ai_summary'] = 'AI screening failed because no valid score, classification, and summary were returned.'
        sheet_data['ai_strengths'] = ''
        sheet_data['ai_concerns'] = 'Missing or invalid LLM output object'
        sheet_data['interview_recommended'] = 'NO'
        sheet_data['status'] = 'screening_error'
        sheet_data['workflow_status'] = 'ERROR'
        sheet_data['error_note'] = 'Missing or invalid LLM output object'

    output_items.append({
        'json': sheet_data
    })

return output_items
